<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Kanban Board</title>
<style>
  body{font-family:Arial,Helvetica,sans-serif;margin:0;padding:20px;background:#f4f4f4;}
  #new-card-container{margin-bottom:15px;display:flex;gap:10px;}
  #new-card{flex:1;padding:8px;border:1px solid #ccc;border-radius:4px;}
  #add-card{padding:8px 12px;background:#28a745;color:white;border:none;border-radius:4px;cursor:pointer;}
  .board{display:flex;gap:15px;justify-content:center;}
  .column{background:white;border-radius:6px;width:300px;box-shadow:0 2px 5px rgba(0,0,0,.1);display:flex;flex-direction:column;}
  .column h2{margin:0;padding:10px;background:#007bff;color:white;font-size:16px;display:flex;justify-content:space-between;align-items:center;border-top-left-radius:6px;border-top-right-radius:6px;}
  .count{background:#ffc107;color:black;padding:2px 6px;border-radius:12px;font-weight:bold;}
  .card-container{flex:1;padding:10px;min-height:200px;display:flex;flex-direction:column;gap:8px;}
  .card{background:#e9ecef;padding:10px;border-radius:4px;cursor:grab;position:relative;}
  .card:hover{box-shadow:0 2px 6px rgba(0,0,0,.15);}
  .card-del{position:absolute;top:5px;right:5px;background:#dc3545;color:white;border:none;padding:2px 4px;border-radius:3px;font-size:12px;cursor:pointer;}
</style>
</head>
<body>

<div id="new-card-container">
  <input type="text" id="new-card" placeholder="New task title...">
  <button id="add-card">Add Card</button>
</div>

<div class="board">
  <div class="column" id="col-todo">
    <h2>To Do <span class="count">0</span></h2>
    <div class="card-container"></div>
  </div>
  <div class="column" id="col-doing">
    <h2>Doing <span class="count">0</span></h2>
    <div class="card-container"></div>
  </div>
  <div class="column" id="col-done">
    <h2>Done <span class="count">0</span></h2>
    <div class="card-container"></div>
  </div>
</div>

<script>
(() => {
  const STORAGE_KEY = 'kanbanState';
  let state = []; // [{id, title, column}]

  function save() { localStorage.setItem(STORAGE_KEY, JSON.stringify(state)); }

  function load() {
    const data = localStorage.getItem(STORAGE_KEY);
    if (data) state = JSON.parse(data);
  }

  function createCardElement(card) {
    const el = document.createElement('div');
    el.className = 'card';
    el.draggable = true;
    el.dataset.id = card.id;

    const titleSpan = document.createElement('span');
    titleSpan.textContent = card.title;
    el.appendChild(titleSpan);

    const delBtn = document.createElement('button');
    delBtn.className = 'card-del';
    delBtn.textContent = '✕';
    delBtn.onclick = () => deleteCard(card.id);
    el.appendChild(delBtn);

    el.ondragstart = (e) => {
      e.dataTransfer.setData('text/plain', card.id);
    };

    return el;
  }

  function render() {
    ['col-todo','col-doing','col-done'].forEach(colId=>{
      const container = document.querySelector(`#${colId} .card-container`);
      container.innerHTML = '';
      state.filter(c=>c.column===colId).forEach(card=>{
        container.appendChild(createCardElement(card));
      });
      // update count
      const countEl = document.querySelector(`#${colId} .count`);
      countEl.textContent = state.filter(c=>c.column===colId).length;
    });
  }

  function addCard(title) {
    if (!title.trim()) return;
    const newCard = {id: Date.now().toString() + Math.random(), title, column:'col-todo'};
    state.push(newCard);
    save();
    render();
  }

  function deleteCard(id) {
    state = state.filter(c=>c.id!==id);
    save();
    render();
  }

  // Drag & Drop handlers
  const columns = document.querySelectorAll('.column .card-container');
  columns.forEach(col=>{
    col.addEventListener('dragover', e => e.preventDefault());
    col.addEventListener('drop', e => {
      e.preventDefault();
      const id = e.dataTransfer.getData('text/plain');
      const card = state.find(c=>c.id===id);
      if (!card) return;
      const newColId = col.parentElement.id;
      if (card.column !== newColId) {
        card.column = newColId;
        save();
        render();
      }
    });
  });

  // UI events
  document.getElementById('add-card').onclick = () => {
    const input = document.getElementById('new-card');
    addCard(input.value);
    input.value = '';
  };
  document.getElementById('new-card').addEventListener('keypress', e=>{
    if (e.key==='Enter') document.getElementById('add-card').click();
  });

  // Init
  load();
  render();
})();
</script>
</body>
</html>
